-- Generated by scripts/export_supabase_seed.mjs. Do not edit manually.
insert into public.quests_pool_cloud (
  id, level, stat_type, energy_cost, reward_energy, is_shadow, is_boss,
  quest_text, low_pressure_variant, advanced_variant, safety_reviewed, content_version
) values
  ('q_c_001', 1, 'charisma', 10, 0, false, false, 'После обычной помощи или услуги скажи: «Спасибо, хорошего дня» чуть теплее, чем обычно.', 'Скажи обычное «спасибо» и спокойно кивни.', 'Добавь одну конкретную благодарность, не задерживая человека.', true, 1),
  ('q_c_002', 1, 'charisma', 10, 0, false, false, 'Сделай короткий комплимент вещи: книге, кружке, значку или принту.', 'Сделай комплимент вещи знакомого человека.', 'Спроси один вопрос о вещи, если человек отвечает охотно.', true, 1),
  ('q_c_003', 1, 'charisma', 10, 0, false, false, 'Поздоровайся с соседом по дому, офису или коворкингу.', 'Поздоровайся без остановки и без продолжения разговора.', 'Добавь короткое ''как день?'' если это уместно.', true, 1),
  ('q_c_004', 1, 'charisma', 10, 0, false, false, 'Скажи одну нейтральную фразу о погоде или месте человеку, который уже рядом.', 'Скажи фразу знакомому или человеку, который сам начал контакт.', 'Поддержи ответ еще одной короткой фразой.', true, 1),
  ('q_c_015', 1, 'charisma', 10, 0, false, false, 'Придержи дверь и спокойно скажи: ''Проходите''.', 'Сделай это без слов, только с улыбкой или кивком.', 'Добавь ''хорошего дня'', если момент естественный.', true, 1),
  ('q_b_002', 1, 'boldness', 10, 0, false, false, 'Задай простой уточняющий вопрос в магазине или кафе.', 'Задай вопрос сотруднику, который уже помогает тебе.', 'После ответа поблагодари полной фразой.', true, 1),
  ('q_b_014', 1, 'boldness', 10, 0, false, false, 'Спроси, где находится нужный отдел, стойка или полка.', 'Спроси у сотрудника на информационной стойке.', 'Уточни один безопасный нюанс после ответа.', true, 1),
  ('q_n_001', 1, 'networking', 10, 0, false, false, 'Попроси рекомендацию кофе, чая, книги или места.', 'Спроси у человека, чья роль уже предполагает помощь с выбором.', 'Скажи, почему выбрал именно эту рекомендацию.', true, 1),
  ('q_n_002', 1, 'networking', 10, 0, false, false, 'Спроси знакомого или коллегу, какое место поблизости ему нравится.', 'Спроси в переписке вместо живого разговора.', 'Попроси объяснить рекомендацию одним предложением.', true, 1),
  ('q_n_003', 1, 'networking', 10, 0, false, false, 'В книжном, кофейне или магазине попроси подсказать один безопасный вариант.', 'Спроси только у сотрудника, который свободен.', 'Назови один критерий: ''что-то спокойное'', ''не слишком сладкое''.', true, 1),
  ('q_c_016', 1, 'charisma', 10, 0, false, false, 'Поблагодари человека за небольшую точность: быстро, аккуратно или понятно.', 'Скажи это знакомому после бытовой помощи.', 'Добавь имя, если оно уже известно из бейджа или знакомства.', true, 1),
  ('q_b_016', 1, 'boldness', 10, 0, false, false, 'Спроси нейтральный маршрут или направление в общественном месте.', 'Спроси у сотрудника стойки информации.', 'Повтори ответ своими словами и поблагодари.', true, 1),
  ('q_n_010', 1, 'networking', 10, 0, false, false, 'Спроси, какой вариант из двух выглядит более практичным.', 'Спроси знакомого человека.', 'Коротко объясни, почему тебе помог ответ.', true, 1),
  ('q_c_005', 2, 'charisma', 25, 0, false, false, 'Сам начни минутный разговор с человеком, которого ещё не знаешь: представься и задай открытый вопрос.', 'Представься одному участнику и задай вопрос о месте, событии или общей теме.', 'Узнай имя и сам закончи разговор фразой «Рад был познакомиться».', true, 1),
  ('q_c_006', 2, 'charisma', 25, 0, false, false, 'Скажи знакомому вживую, за какое конкретное качество ты его уважаешь. Без шутки и обесценивания в конце.', 'Скажи одну прямую фразу: «Я ценю в тебе [конкретное качество]».', 'Добавь один реальный пример, когда это качество проявилось.', true, 1),
  ('q_c_007', 2, 'charisma', 25, 0, false, false, 'В живом разговоре задай открытый вопрос и выдержи две секунды тишины, не отвечая за собеседника.', 'Задай вопрос знакомому и не заполняй первую паузу словами-паразитами.', 'После ответа задай один уточняющий вопрос и снова выдержи паузу.', true, 1),
  ('q_c_008', 2, 'charisma', 25, 0, false, false, 'Познакомься с новым человеком в общей среде, спроси имя и один раз используй его в разговоре.', 'Представься первым и спроси: «Как тебя зовут?»', 'Запомни имя без записи и попрощайся, обратившись по имени.', true, 1),
  ('q_b_004', 2, 'boldness', 25, 0, false, false, 'На открытом событии начни разговор первым до того, как к тебе обратятся.', 'Подойди к одному участнику и спроси, что привело его на событие.', 'Представься, узнай имя и удержи разговор две минуты.', true, 1),
  ('q_b_017', 2, 'boldness', 25, 0, false, false, 'В разговоре выбери один из двух вариантов вслух и дай одну ясную причину, не прячась за «мне всё равно».', 'Назови знакомому свой выбор и одну причину без долгих оговорок.', 'Попроси собеседника оспорить выбор и спокойно ответь одной фразой.', true, 1),
  ('q_b_018', 2, 'boldness', 25, 0, false, false, 'Попроси знакомого о небольшой конкретной помощи и не объясняй просьбу дольше одного предложения.', 'Сформулируй просьбу с чётким действием и сроком в переписке.', 'Спроси вживую и спокойно прими как согласие, так и отказ.', true, 1),
  ('q_b_019', 2, 'boldness', 25, 0, false, false, 'В общей зоне открытого события подойди к одному свободному участнику, представься и начни короткий разговор.', 'Представься одному участнику, который не занят разговором или работой.', 'Узнай имя и одну причину, зачем человек пришёл на событие.', true, 1),
  ('q_n_004', 2, 'networking', 25, 0, false, false, 'На событии спроси участника, как он получил один навык или результат, который тебе интересен.', 'Задай вопрос одному знакомому участнику и попроси назвать первый шаг.', 'Назови свою цель и попроси указать одну ошибку, которой стоит избежать.', true, 1),
  ('q_n_005', 2, 'networking', 25, 0, false, false, 'На событии подойди к участнику и попроси назвать один ресурс по общей теме.', 'Спроси одного участника: «Что по этой теме реально стоит посмотреть?»', 'Объясни свой контекст одной фразой и попроси рекомендацию именно под него.', true, 1),
  ('q_n_006', 2, 'networking', 25, 0, false, false, 'Попроси человека с нужным опытом дать один честный совет по твоей реальной задаче.', 'Сформулируй запрос в переписке: контекст, один вопрос, без длинного вступления.', 'После ответа назови вслух шаг, который сделаешь в ближайшие сутки.', true, 1),
  ('q_c_012', 2, 'charisma', 25, 0, false, false, 'Отправь знакомому голосовое с конкретным приглашением: действие, место и время.', 'Запиши голосом конкретный план на ближайшие три дня без «как-нибудь».', 'Попроси ответить «да» или предложить один другой слот.', true, 1),
  ('q_b_020', 2, 'boldness', 25, 0, false, false, 'Перед открытым событием подойди к стоящей открытой группе: «Можно присоединиться к разговору?»', 'Спроси одного свободного участника, о чём сейчас говорит группа.', 'После явного согласия представься и первым задай вопрос общей группе.', true, 1),
  ('q_c_013', 2, 'charisma', 25, 0, false, false, 'Скажи знакомому, что не согласен с одним небольшим тезисом, и дай одну спокойную причину.', 'Начни с «Я вижу это иначе» и объясни позицию одним предложением.', 'Попроси собеседника назвать сильнейшую причину своей позиции и дослушай.', true, 1),
  ('q_c_009', 3, 'charisma', 50, 0, false, false, 'Сделай новому знакомому прямой комплимент его выбору, мысли или стилю и не превращай его в шутку.', 'Отметь одну конкретную деталь и остановись после фразы.', 'Добавь короткий вопрос, который продолжает тему комплимента.', true, 1),
  ('q_c_017', 3, 'charisma', 50, 0, false, false, 'Сам начни трёхминутный разговор с новым человеком, смени тему хотя бы один раз и сам закончи контакт.', 'Проведи двухминутный разговор: представься, задай два вопроса, попрощайся первым.', 'Найди одну общую тему и предложи конкретный способ продолжить контакт.', true, 1),
  ('q_b_021', 3, 'boldness', 50, 0, false, false, 'На мероприятии начни первый разговор до того, как возьмёшь телефон в руки или спрячешься у стены.', 'Подойди к одному участнику, представься и спроси, зачем он пришёл.', 'Удержи разговор три минуты и познакомь собеседника ещё с одним человеком.', true, 1),
  ('q_b_009', 3, 'boldness', 50, 0, false, false, 'На естественной паузе в групповой беседе возьми слово и задай вопрос всей группе.', 'Задай вопрос малой группе из 2–3 человек, не обращаясь только к знакомому.', 'Сначала назови свой короткий тезис, затем попроси группу его оспорить.', true, 1),
  ('q_b_010', 3, 'boldness', 50, 0, false, false, 'Подойди к группе перед занятием или событием и прямо спроси: «Можно к вам присоединиться?»', 'Спроси это у пары участников, стоящих в открытой общей зоне.', 'После согласия представься и первым внеси одну мысль в разговор.', true, 1),
  ('q_n_007', 3, 'networking', 50, 0, false, false, 'После лекции или встречи подойди к человеку с опытом и попроси один совет по своей реальной задаче.', 'Задай один конкретный вопрос участнику, чьё выступление или опыт тебе понятен.', 'Коротко представься, назови цель и попроси указать твою вероятную ошибку.', true, 1),
  ('q_n_008', 3, 'networking', 50, 0, false, false, 'После взаимного разговора сам предложи обменяться контактами и назови конкретную причину продолжить общение.', 'Попроси публичный профиль и скажи, какую тему хочешь продолжить.', 'Сразу предложи конкретный следующий шаг: сообщение, созвон или встречу.', true, 1),
  ('q_n_009', 3, 'networking', 50, 0, false, false, 'Попроси организатора или знакомого представить тебя одному человеку по конкретной теме.', 'Спроси, кто из участников разбирается в нужной тебе теме, и найди этого человека.', 'Подойди к рекомендованному человеку, назови связующего и начни разговор сам.', true, 1),
  ('q_b_013', 3, 'boldness', 50, 0, false, false, 'В малой группе выскажи позицию, которую не все поддержат, и дай одну ясную причину без извинений.', 'Выскажи отличный от большинства взгляд группе из 2–3 человек.', 'Попроси самый сильный контраргумент и ответь только после того, как перескажешь его точно.', true, 1),
  ('q_c_014', 3, 'charisma', 50, 0, false, false, 'Пригласи знакомого на конкретную встречу: действие, место и время. Попроси прямой ответ.', 'Сделай конкретное приглашение в сообщении без «как-нибудь» и «если что».', 'Предложи два точных слота и спокойно закрой вопрос, если оба не подходят.', true, 1),
  ('q_s_001', 1, 'charisma', 0, 5, true, false, 'Напиши черновик теплого спасибо человеку, который недавно помог.', 'Оставь черновик у себя, отправлять не обязательно.', 'Отправь сообщение, если это спокойно и уместно.', true, 1),
  ('q_s_002', 1, 'boldness', 0, 5, true, false, 'Произнеси вслух одну фразу для будущего small talk.', 'Произнеси ее шепотом или мысленно.', 'Запиши себя и удали запись после прослушивания.', true, 1),
  ('q_s_003', 1, 'networking', 0, 5, true, false, 'Составь три нейтральных вопроса, которые можно задать на событии.', 'Составь один вопрос.', 'Добавь короткое продолжение для каждого вопроса.', true, 1),
  ('q_s_004', 1, 'charisma', 0, 5, true, false, 'Вспомни один удачный разговор и запиши, что в нем помогло.', 'Запиши только одно слово.', 'Сформулируй один прием, который повторишь.', true, 1),
  ('q_s_005', 1, 'boldness', 0, 5, true, false, 'Выбери безопасное место, где завтра можно выполнить легкий квест.', 'Выбери место без точного времени.', 'Добавь время и запасной вариант.', true, 1),
  ('q_s_006', 2, 'networking', 0, 5, true, false, 'Подготовь список из трех людей, у кого можно спросить рекомендацию.', 'Запиши одного человека.', 'Подготовь точную фразу для первого сообщения.', true, 1),
  ('q_s_007', 2, 'charisma', 0, 5, true, false, 'Напиши два варианта комплимента вещи, а не человеку.', 'Напиши один вариант.', 'Сделай варианты короче пяти слов.', true, 1),
  ('q_s_008', 2, 'boldness', 0, 5, true, false, 'Отрепетируй фразу отказа: ''Спасибо, я пока не готов, попробую позже''.', 'Прочитай фразу глазами.', 'Произнеси ее спокойно три раза.', true, 1),
  ('q_s_009', 2, 'networking', 0, 5, true, false, 'Найди одно локальное событие, где можно безопасно поговорить с людьми.', 'Просто сохрани ссылку или название.', 'Запиши один вопрос для участника события.', true, 1),
  ('q_s_010', 2, 'charisma', 0, 5, true, false, 'Составь короткое ''спасибо'' с конкретикой для персонала или курьера.', 'Оставь фразу в заметках.', 'Скажи ее при следующем подходящем случае.', true, 1),
  ('q_s_011', 2, 'boldness', 0, 5, true, false, 'Отметь три ситуации, где можно задать нейтральный вопрос без давления.', 'Отметь одну ситуацию.', 'Подбери фразу для каждой ситуации.', true, 1),
  ('q_s_012', 2, 'networking', 0, 5, true, false, 'Подготовь короткое представление себя для мероприятия или коворкинга.', 'Составь версию из пяти слов.', 'Добавь один вопрос после представления.', true, 1),
  ('q_s_013', 2, 'charisma', 0, 5, true, false, 'Сделай мини-разбор: где твои границы в социальных квестах сегодня.', 'Отметь только один запретный для себя формат.', 'Запиши один комфортный формат на завтра.', true, 1),
  ('boss_group_entry', 3, 'boldness', 50, 0, false, true, 'На открытом мероприятии подойди к группе из 2–3 человек: «Привет, я [имя]. О чём говорите?»', 'Подойди к одному участнику открытого события: «Привет, я [имя]. Как тебе здесь?»', 'Останься в разговоре две минуты и узнай имя хотя бы одного человека.', true, 1),
  ('boss_clear_position', 3, 'networking', 50, 0, false, true, 'В живом разговоре выскажи короткое непопулярное, но уважительное мнение и не смягчай его фразой «может, я не прав».', 'Выскажи знакомому позицию, которую обычно оставляешь при себе, и остановись после одной ясной причины.', 'Попроси собеседника дать сильнейший контраргумент и выслушай его без защиты.', true, 1),
  ('boss_direct_invite', 3, 'boldness', 50, 0, false, true, 'Предложи знакомому конкретный спонтанный план: место, время и действие. Не оставляй предложение размытым.', 'Предложи конкретный план на завтра и попроси ответить «да» или «нет».', 'Пригласи второго человека и сам зафиксируй общий план в сообщении.', true, 1),
  ('boss_contact_exit', 3, 'charisma', 50, 0, false, true, 'Сам начни разговор с незнакомым участником открытого события и сам закончи его через две минуты: «Рад был познакомиться».', 'Проведи минутный разговор с одним участником: представься, задай один вопрос и сам попрощайся.', 'Обменяйтесь именами, найди одну общую тему и закончи разговор первым.', true, 1),
  ('boss_join_space', 3, 'networking', 50, 0, false, true, 'Перед открытым событием подойди к явно открытой группе и спроси: «Можно к вам присоединиться?» Спокойно прими любой ответ.', 'Подойди к одному свободному участнику общей зоны: «Привет, можно присоединиться к разговору?»', 'После согласия добавь одну релевантную мысль или вопрос по общей теме.', true, 1)
on conflict (id) do update set
  level = excluded.level,
  stat_type = excluded.stat_type,
  energy_cost = excluded.energy_cost,
  reward_energy = excluded.reward_energy,
  is_shadow = excluded.is_shadow,
  is_boss = excluded.is_boss,
  quest_text = excluded.quest_text,
  low_pressure_variant = excluded.low_pressure_variant,
  advanced_variant = excluded.advanced_variant,
  safety_reviewed = excluded.safety_reviewed,
  content_version = excluded.content_version,
  updated_at = now();
